using UnityEngine;
using System.Linq;
using FL.Gameplay.Modules.BigWorld;
using FL.Gameplay.Vehicle;
public class Script
{
    public static object Main()
    {
        try
        {
            var player = PlayerManager.Controller;
            if (player == null) return "No player";
            var playerPos = player.GetTransform().position;
            var vehicles = Object.FindObjectsOfType<Vehicle>();
            if (vehicles == null || vehicles.Length == 0) return "No vehicles found";
            var result = "Player=" + playerPos + " Vehicles=" + vehicles.Length + "\n";
            var sorted = vehicles.OrderBy(v => Vector3.Distance(v.transform.position, playerPos)).Take(5);
            foreach (var v in sorted)
            {
                var dist = Vector3.Distance(v.transform.position, playerPos);
                result += "  Dist=" + dist.ToString("F1") + " Pos=" + v.transform.position + " isTraffic=" + v.isControlledByTraffic + " name=" + v.name + "\n";
            }
            return result;
        }
        catch (System.Exception ex) { return "Error: " + ex.Message; }
    }
}
